package com.granpa.pumpselector;
import android.app.*;import android.graphics.*;import android.view.*;import android.widget.*;import java.util.*;
public class OptionAdapter extends ArrayAdapter<Option>{Activity a;List<Option> opts;public OptionAdapter(Activity a,List<Option> o){super(a,android.R.layout.simple_spinner_item,o);this.a=a;opts=o;}
 public View getView(int pos,View convert,ViewGroup parent){return itemView(pos,false);} public View getDropDownView(int pos,View convert,ViewGroup parent){return itemView(pos,true);} private View itemView(int pos,boolean dropdown){Option it=opts.get(pos);LinearLayout box=new LinearLayout(a);box.setOrientation(LinearLayout.VERTICAL);box.setGravity(Gravity.CENTER_VERTICAL);box.setPadding(Ui.dp(a,14),Ui.dp(a,dropdown?12:8),Ui.dp(a,14),Ui.dp(a,dropdown?12:8));box.setMinimumHeight(Ui.dp(a,dropdown?76:62));box.setBackgroundColor(Color.WHITE);TextView title=Ui.text(a,it.label,16,it.mainCategory?Ui.BLUE:Ui.TEXT,Typeface.BOLD);title.setSingleLine(false);box.addView(title);if(it.detail!=null&&!it.detail.isEmpty()){TextView d=Ui.text(a,it.detail,12,Ui.MUTED,Typeface.NORMAL);d.setSingleLine(false);box.addView(d);}return box;}
}
